patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..fae9743ebe2b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4516,6 +4516,20 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
     std::swap(Op0, Op1);
     Pred = ICmpInst::getSwappedPredicate(Pred);
   }
+
+  // icmp ((~X) ^ Y) cmp ~Z --> icmp (X ^ Y) cmp' Z
+  // where cmp' is the swapped predicate
+  Value *X, *Y, *Z;
+  if (match(Op0, m_c_Xor(m_Not(m_Value(X)), m_Value(Y))) &&
+      match(Op1, m_Not(m_Value(Z)))) {
+    // Only handle relational predicates (slt, ult, sge, uge, sle, ule, sgt, ugt)
+    // Equality predicates (eq, ne) are handled elsewhere
+    if (ICmpInst::isEquality(Pred))
+      return nullptr;
+    Value *Xor = IC.Builder.CreateXor(X, Y);
+    return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Xor, Z);
+  }
+
   if (!match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A))))
     return nullptr;

