  1319 | Instruction *InstCombinerImpl::foldICmpWithConstant(ICmpInst &Cmp) {
  1320 |   // Match the following pattern, which is a common idiom when writing
  1321 |   // overflow-safe integer arithmetic functions. The source performs an addition
  1322 |   // in wider type and explicitly checks for overflow using comparisons against
  1323 |   // INT_MIN and INT_MAX. Simplify by using the sadd_with_overflow intrinsic.
  1324 |   //
  1325 |   // TODO: This could probably be generalized to handle other overflow-safe
  1326 |   // operations if we worked out the formulas to compute the appropriate magic
  1327 |   // constants.
  1328 |   //
  1329 |   // sum = a + b
  1330 |   // if (sum+128 >u 255)  ...  -> llvm.sadd.with.overflow.i8
  1331 |   CmpInst::Predicate Pred = Cmp.getPredicate();
  1332 |   Value *Op0 = Cmp.getOperand(0), *Op1 = Cmp.getOperand(1);
  1333 |   Value *A, *B;
  1334 |   ConstantInt *CI, *CI2; // I = icmp ugt (add (add A, B), CI2), CI
  1335 |   if (Pred == ICmpInst::ICMP_UGT && match(Op1, m_ConstantInt(CI)) &&
  1336 |       match(Op0, m_Add(m_Add(m_Value(A), m_Value(B)), m_ConstantInt(CI2))))
  1337 |     if (Instruction *Res = processUGT_ADDCST_ADD(Cmp, A, B, CI2, CI, *this))
  1338 |       return Res;
  1339 | 
  1340 |   // icmp(phi(C1, C2, ...), C) -> phi(icmp(C1, C), icmp(C2, C), ...).
  1341 |   Constant *C = dyn_cast<Constant>(Op1);
  1342 |   if (!C)
  1343 |     return nullptr;
  1344 | 
  1345 |   if (auto *Phi = dyn_cast<PHINode>(Op0))
  1346 |     if (all_of(Phi->operands(), [](Value *V) { return isa<Constant>(V); })) {
  1347 |       SmallVector<Constant *> Ops;
  1348 |       for (Value *V : Phi->incoming_values()) {
  1349 |         Constant *Res =
  1350 |             ConstantFoldCompareInstOperands(Pred, cast<Constant>(V), C, DL);
  1351 |         if (!Res)
  1352 |           return nullptr;
  1353 |         Ops.push_back(Res);
  1354 |       }
  1355 |       Builder.SetInsertPoint(Phi);
  1356 |       PHINode *NewPhi = Builder.CreatePHI(Cmp.getType(), Phi->getNumOperands());
  1357 |       for (auto [V, Pred] : zip(Ops, Phi->blocks()))
  1358 |         NewPhi->addIncoming(V, Pred);
  1359 |       return replaceInstUsesWith(Cmp, NewPhi);
  1360 |     }
